const body = $input.item.json.body || $input.item.json;

if (!body.subject && !body.emailBody) {
  throw new Error('Email subject or body is required');
}

const emailText = `${body.subject || ''} ${body.emailBody || body.body || ''}`;

// Extract URLs
const urlRegex = /https?:\/\/[^\s<>"']+/gi;
const extractedUrls = [...new Set(emailText.match(urlRegex) || [])].slice(0, 15);

// Extract domains
const domains = [...new Set(extractedUrls.map(url => {
  try { return new URL(url).hostname; } catch(e) { return null; }
}).filter(Boolean))];

// Phishing keyword check
const phishKeywords = [
  'urgent','verify your account','click here','update payment',
  'suspended','confirm identity','act now','password expired',
  'invoice attached','wire transfer','bitcoin','gift card',
  'winner','free gift','limited offer','account compromised'
];
const keywordsHit = phishKeywords.filter(kw =>
  emailText.toLowerCase().includes(kw)
);

// Sender vs reply-to mismatch
const senderEmail = (body.senderEmail || body.from || '').toLowerCase();
const replyTo = (body.replyTo || '').toLowerCase();
const senderDomain = senderEmail.split('@')[1] || '';
const replyDomain = replyTo.split('@')[1] || '';
const domainMismatch = !!(replyTo && senderDomain && replyDomain && senderDomain !== replyDomain);

// Suspicious attachments
const dangerExts = /\.(exe|js|vbs|ps1|bat|cmd|scr|jar|zip|rar|hta)$/i;
const suspAttachments = (body.attachments || []).filter(a => dangerExts.test(a.filename || ''));

return {
  json: {
    emailRecord: {
      emailId: `PHISH-${Date.now()}-${Math.random().toString(36).substr(2,6).toUpperCase()}`,
      subject: body.subject || '(No Subject)',
      senderEmail,
      senderName: body.senderName || '',
      recipientEmail: body.recipientEmail || body.to || '',
      replyTo,
      emailBody: emailText.substring(0, 2500),
      extractedUrls,
      domains,
      keywordsHit,
      keywordCount: keywordsHit.length,
      domainMismatch,
      suspAttachmentCount: suspAttachments.length,
      suspAttachmentNames: suspAttachments.map(a => a.filename),
      receivedAt: body.receivedAt || new Date().toISOString()
    }
  }
};

parameters.text:
=You are an expert cybersecurity analyst specializing in phishing detection.

Analyze this email and return a structured phishing risk assessment.

**Email:**
- Subject: {{ $json.emailRecord.subject }}
- From: {{ $json.emailRecord.senderEmail }}
- Reply-To: {{ $json.emailRecord.replyTo || 'same as sender' }}
- Domain Mismatch: {{ $json.emailRecord.domainMismatch }}
- Keywords Triggered ({{ $json.emailRecord.keywordCount }}): {{ $json.emailRecord.keywordsHit.join(', ') || 'none' }}
- URLs Found: {{ $json.emailRecord.extractedUrls.slice(0,5).join(', ') || 'none' }}
- Suspicious Attachments: {{ $json.emailRecord.suspAttachmentCount }} — {{ $json.emailRecord.suspAttachmentNames.join(', ') || 'none' }}
- Body: {{ $json.emailRecord.emailBody.substring(0, 1500) }}

**Respond in JSON only:**
{
  "riskScore": 85,
  "riskLevel": "HIGH",
  "attackType": "credential_phishing",
  "confidenceLevel": 91,
  "isPhishing": true,
  "impersonatedBrand": "Microsoft",
  "socialEngineeringTactics": ["urgency", "fear"],
  "credentialHarvestingRisk": true,
  "recommendation": "QUARANTINE",
  "userWarningMessage": "Short plain-English warning for the recipient",
  "socSummary": "2-sentence technical summary for SOC team"
}

parameters.jsCode:
const aiResp = $input.item.json;
let aiText = aiResp.response || aiResp.output || aiResp.text || '';
if (aiResp.content && Array.isArray(aiResp.content)) {
  aiText = aiResp.content[0]?.text || '';
}
const clean = aiText.replace(/```json\s*/g,'').replace(/```\s*/g,'').trim();

let analysis;
try { analysis = JSON.parse(clean); }
catch(e) { throw new Error(`Parse failed: ${e.message}. Raw: ${clean.substring(0,150)}`); }

const vtResult = $('VirusTotal URL Scan').item.json;
const vtMalicious = vtResult?.data?.attributes?.last_analysis_stats?.malicious || 0;
const vtSuspicious = vtResult?.data?.attributes?.last_analysis_stats?.suspicious || 0;

let score = analysis.riskScore || 0;
if (vtMalicious > 0) score = Math.min(100, score + 20);
if (vtSuspicious > 0) score = Math.min(100, score + 10);

const riskLevel = score >= 75 ? 'HIGH' : score >= 40 ? 'MEDIUM' : 'LOW';
const action = riskLevel === 'HIGH' ? 'QUARANTINE' : riskLevel === 'MEDIUM' ? 'FLAG' : 'ALLOW';

const emailRecord = $('Extract IOCs & Normalize').item.json.emailRecord;

return {
  json: {
    emailRecord,
    analysis: { ...analysis, riskScore: score, riskLevel },
    vtMalicious,
    vtSuspicious,
    riskLevel,
    finalScore: score,
    action,
    analyzedAt: new Date().toISOString()
  }
};

